import{_ as t,o,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Coach Notes","description":"","frontmatter":{},"headers":[],"relativePath":"coach-notes/index.md","filePath":"coach-notes/index.md"}'),s={name:"coach-notes/index.md"};function i(n,e,c,l,d,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="coach-notes" tabindex="-1">Coach Notes <a class="header-anchor" href="#coach-notes" aria-label="Permalink to &quot;Coach Notes&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Coach Notes captures coaching observations and connects them to training plans. Notes can be entered as text, spoken as voice notes, or processed through AI to extract structured player observations from free-form text.</p><h2 id="adding-notes" tabindex="-1">Adding Notes <a class="header-anchor" href="#adding-notes" aria-label="Permalink to &quot;Adding Notes&quot;">​</a></h2><p>Notes can be added from multiple places:</p><ul><li><strong>Quick Note button</strong> on the dashboard</li><li><strong>Notes tab</strong> on any player profile</li><li><strong>Notes hub</strong> via the bottom navigation More menu</li><li><strong>Voice Note</strong> button for spoken observations</li><li><strong>End of practice</strong> prompt in Individual Practice sessions</li></ul><h2 id="note-types" tabindex="-1">Note Types <a class="header-anchor" href="#note-types" aria-label="Permalink to &quot;Note Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Team</td><td>General team observation</td></tr><tr><td>Player</td><td>Observation about a specific player</td></tr><tr><td>Game</td><td>Note tied to a specific game</td></tr><tr><td>Practice</td><td>Note tied to a practice session</td></tr></tbody></table><h2 id="ai-note-processing" tabindex="-1">AI Note Processing <a class="header-anchor" href="#ai-note-processing" aria-label="Permalink to &quot;AI Note Processing&quot;">​</a></h2><p>The AI processing feature extracts structured player observations from free-form notes. This is useful when you have written or spoken extended observations across multiple players.</p><p><strong>How to use it:</strong></p><ol><li>Navigate to Notes hub → <strong>Process Notes with AI</strong></li><li>Type or paste your notes (up to 2,000 characters)</li><li>Select the date range for context — previous notes from that period are included to help identify patterns</li><li>Tap <strong>Process Notes with AI</strong></li><li>Review the extracted observations on the results screen</li><li>Save individual observations or create training plans directly</li></ol><h2 id="pattern-recognition" tabindex="-1">Pattern Recognition <a class="header-anchor" href="#pattern-recognition" aria-label="Permalink to &quot;Pattern Recognition&quot;">​</a></h2><p>When you include previous notes as context the AI identifies recurring issues:</p><ul><li>Issues noted multiple times are flagged as <strong>Recurring</strong></li><li>Issues that appear resolved are flagged as <strong>Improving</strong></li><li>The overall pattern summary appears at the top of results</li></ul><h2 id="voice-notes" tabindex="-1">Voice Notes <a class="header-anchor" href="#voice-notes" aria-label="Permalink to &quot;Voice Notes&quot;">​</a></h2><p>Tap <strong>Voice Note</strong> to speak your observations directly. The app captures your speech and sends it through the same AI processing pipeline. Ideal for coaches who want to dictate observations right after a game or practice.</p><p><strong>On mobile:</strong> The keyboard appears with the microphone icon ready. Tap the keyboard microphone, speak your observations freely, then tap <strong>Process Notes with AI</strong> when done.</p>',18)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
